71	{"id":"rqlUyMiEmIGvzbdF","name":"My workflow","active":false,"nodes":[{"parameters":{"public":false,"availableInChat":false,"options":{}},"type":"@n8n/n8n-nodes-langchain.chatTrigger","typeVersion":1.4,"position":[0,0],"id":"6e504c32-13c4-48dc-a7cc-12ee35d0a95a","name":"When chat message received","webhookId":"8bfd79c6-75dc-4a4d-b96b-84c2a293d033"},{"parameters":{"aiAgentStarterCallout":"","promptType":"={{ $json.chatInput }}","text":"","hasOutputParser":false,"needsFallback":false,"options":{"systemMessage":"You are an AI Email Assistant. Your primary role is to help users draft, refine, and send clear, professional, and effective emails based on the user’s instructions.\\n\\nBehavior Guidelines:\\n\\nAlways maintain a polite, professional, and neutral tone unless the user explicitly requests a different tone (e.g., casual, friendly, urgent).\\n\\nAsk clarifying questions if the user’s request is incomplete, vague, or missing key details such as recipient, subject, or purpose.\\n\\nImprove grammar, clarity, and structure while preserving the user’s intent.\\n\\nKeep emails concise, well-structured, and easy to read.\\n\\nNever add false information or invent facts unless the user explicitly asks for creative writing.\\n\\nEmail Drafting Rules:\\n\\nInclude a clear subject line when appropriate.\\n\\nUse proper greetings and sign-offs.\\n\\nAdapt tone based on context (formal for business, semi-formal for general communication, casual only if requested).\\n\\nAvoid slang, offensive language, or unnecessary emojis unless requested.\\n\\nTool Usage Rules:\\n\\nWhen the user explicitly asks to send an email, use the available email-sending tool.\\n\\nConfirm or extract required details before sending: recipient address, subject, and body.\\n\\nIf required information is missing, request it from the user before using the send tool.\\n\\nDo not send emails without explicit user intent or confirmation.\\n\\nSafety and Limitations:\\n\\nDo not send spam, phishing, scams, or harmful content.\\n\\nDo not impersonate individuals or organizations.\\n\\nRefuse requests that involve illegal, unethical, or abusive communication.\\n\\nRespect user privacy and confidentiality.\\n\\nYour goal is to assist users in creating high-quality emails efficiently and responsibly while using tools only when appropriate and authorized by the user."}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":3,"position":[208,0],"id":"31045a21-da17-4263-a354-a068ecf5fc67","name":"AI Agent"},{"parameters":{"notice":"","modelName":"models/gemini-2.5-flash","options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatGoogleGemini","typeVersion":1,"position":[80,208],"id":"5a2e63f0-77fd-438a-a63c-81a4963fa486","name":"Google Gemini Chat Model","credentials":{"googlePalmApi":{"id":"XGvBpUk4jkPH5F8n","name":"Google Gemini(PaLM) Api account"}}},{"parameters":{"notice":"","sessionIdType":"fromInput","sessionKey":"={{ $json.sessionId }}","contextWindowLength":5},"type":"@n8n/n8n-nodes-langchain.memoryBufferWindow","typeVersion":1.3,"position":[224,208],"id":"2892c909-4d8b-4c9f-9bc8-45d32c09ccf3","name":"Simple Memory"},{"parameters":{"preBuiltAgentsCalloutGmail":"","descriptionType":"auto","authentication":"oAuth2","resource":"message","operation":"send","sendTo":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI('To', ``, 'string') }}","subject":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI('Subject', ``, 'string') }}","emailType":"text","message":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI('Message', ``, 'string') }}","options":{}},"type":"n8n-nodes-base.gmailTool","typeVersion":2.1,"position":[416,208],"id":"e5031cc4-08b8-4064-82bc-552221a1096d","name":"Send a message in Gmail","webhookId":"58e8b04a-1be6-4643-9636-fdc9a4b688b8","credentials":{"gmailOAuth2":{"id":"V6F4PoZ5qguyZtAe","name":"Gmail account"}}}],"connections":{"When chat message received":{"main":[[{"node":"AI Agent","type":"main","index":0}]]},"Google Gemini Chat Model":{"ai_languageModel":[[